import json
import os
import time

from diploma_thesis.analysis.statistics import compute_and_print_stats
from diploma_thesis.api.clinvar import (clinvar_efetch, convert_pubmed_ids,
                                        extract_pubmed_ids)
from diploma_thesis.api.litvar import get_litvar_ids_for_query
from diploma_thesis.api.variomes import (fetch_variomes_data,
                                         parse_variomes_data)
from diploma_thesis.core.models import Variant
from diploma_thesis.settings import DATA_DIR, logger


def get_model_output_ids() -> dict[str, list]:
    variant2ids = {}
    for path in os.listdir(DATA_DIR / "15variants_data_evaluated_by_molecular_geneticist"):
        article_ids = []
        with open(DATA_DIR / "15variants_data_evaluated_by_molecular_geneticist" / path, "r", encoding="utf-8") as f:
            data = json.load(f)

        data = data[0]  # IMPORTANT! The data are stored as a list with one element

        variant = data["variant"]
        for article in data.get("article_mentions"):
            art_id = article["article_id"]
            article_ids.append(art_id)

        variant2ids[variant] = list(set(article_ids))

    return variant2ids


def get_variomes_ids() -> dict[str, list]:
    variant2ids = {}
    with open(DATA_DIR / "15variants.txt", "r", encoding="utf-8") as f:
        lines = [line.strip() for line in f.readlines()]

    for line in lines:
        if line.split(" ")[2] == "p":
            variant = Variant(line.split(" ")[0], line.split(" ")[1], "protein")
        else:
            variant = Variant(line.split(" ")[0], line.split(" ")[1], "transcript")

        articles = parse_variomes_data(fetch_variomes_data(variant), variant)

        variomes_ids = [a.pmcid or a.pmid for a in articles]
        variant2ids[variant.variant_string] = variomes_ids

    return variant2ids


def get_before_llm_calls_ids() -> dict[str, list]:
    variant2ids = {}
    for path in os.listdir(DATA_DIR / "15variants_data_evaluated_by_molecular_geneticist"):
        with open(DATA_DIR / "15variants_data_evaluated_by_molecular_geneticist" / path, "r", encoding="utf-8") as f:
            data = json.load(f)

        data = data[0]  # IMPORTANT! The data are stored as a list with one element

        variant = data["variant"]
        article_ids = [a["pmcid"] or a["pmid"] for a in data.get("articles")]

        variant2ids[variant] = list(set(article_ids))

    return variant2ids


def get_clinvar_ids() -> dict[str, list]:
    variant2ids = {}

    # we have to do it manually because the clinvar efetch returns also non-matching variants
    variant2clinvar_ids = {
        "APC c.487C>T": [217991],
        "ATM c.829G>T": [234216],
        "BRCA1 R7C": [37440],
        "BARD1 c.1670G>C": [8045],
        "CDH1 c.8C>G": [142469],
        "EPCAM c.556-14A>G": [157603],
        "BRCA2 c.1141G>A": [91747],
        "MLH1 c.-42C>T": [89593],
        "MSH2 p.Met1Leu": [90834, 90832],
        "MSH6 p.D180D": [36597],
        "PALB2 G998E": [126699],
        "POLE A252V": [380210],
        "RAD51C c.577C>T": [140849],
        "TP53 c.666G>A": [187714]
    }
    for variant, clinvar_ids in variant2clinvar_ids.items():
        # print("variant", variant)
        root = clinvar_efetch(variant, clinvar_ids)
        extracted = extract_pubmed_ids(root)
        article_ids = convert_pubmed_ids(extracted)
        # print("converted", article_ids)
        variant2ids[variant] = article_ids

    return variant2ids


def get_litvar_ids() -> dict[str, list]:
    variant2ids = {}
    with open(DATA_DIR / "15variants.txt", "r", encoding="utf-8") as f:
        lines = [line.strip() for line in f.readlines()]

    for line in lines:
        query = line.split(" ")[0] + " " + line.split(" ")[1]
        litvar_ids = get_litvar_ids_for_query(query)
        variant2ids[query] = litvar_ids

    return variant2ids


def compare_ids(model_output_ids: dict, clinvar_ids: dict, litvar_ids: dict, variomes_ids: dict, before_llm_calls_ids: dict):
    """
    recall_m_c: kolik z clinvar (=„oficiálně známých“) článků model našel; poměr článků z modelu v clinvaru
    precision_m_c: kolik clinvar článků bylo v modelu; poměr clinvar článků vzhledem k počtu nalezených článků; nízké číslo může jen znamenat, že jsem našel nové články, které v clinvaru nejsou a to je fajn
    noise: kolikrát méně jsem našel článků než LitVar - tj. za předpokladu, že zjistím, že ty mnou nalezené jsou relevantní, tak kolikrát jsem snížil počet článků na prohledání
                když předpokládám, že ty ostatní z litvaru jsou nerelevantní... což nemůžu asi

    https://gemini.google.com/share/abd46ddaf34e

    """
    variant2all_ids: dict[str, dict[str, set]] = {}
    for variant, model_ids in model_output_ids.items():
        variant2all_ids[variant] = {
            "model_ids": set(model_ids),
            "clinvar_ids": set(clinvar_ids.get(variant, [])),
            "litvar_ids": set(litvar_ids.get(variant, [])),
            "variomes_ids": set(variomes_ids.get(variant, [])),
            "before_llm_calls_ids": set(before_llm_calls_ids.get(variant, [])),
        }

    [print(key, value) for key, value in variant2all_ids.items()]

    recalls_m_c = []
    recalls_v_c = []
    recalls_blc_c = []
    precisions_m_c = []
    noises = []
    for variant, ids_dict in variant2all_ids.items():
        model = ids_dict["model_ids"]
        clinvar = ids_dict["clinvar_ids"]
        litvar = ids_dict["litvar_ids"]
        variomes = ids_dict["variomes_ids"]
        before_llm_calls = ids_dict["before_llm_calls_ids"]

        recall_m_c = 0
        recall_v_c = 0
        recall_blc_c = 0
        precision_m_c = 0
        noise = 0
        if len(clinvar) > 0:
            recall_m_c = len(set.intersection(model, clinvar)) / len(clinvar)
            recall_v_c = len(set.intersection(variomes, clinvar)) / len(clinvar)
            recall_blc_c = len(set.intersection(before_llm_calls, clinvar)) / len(clinvar)
        if len(model) > 0:
            precision_m_c = len(set.intersection(model, clinvar)) / len(model)
        if len(model - clinvar) > 0:
            noise = len(litvar - clinvar) / len(model - clinvar)

        print(variant)
        print(f"recall_m_c: {recall_m_c}")
        print(f"recall_v_c: {recall_v_c}")
        print(f"recall_blc_c: {recall_blc_c}")
        print(f"precision_m_c: {precision_m_c}")
        print(f"noise: {noise}")
        print("----------------------------------")

        recalls_m_c.append(recall_m_c)
        recalls_v_c.append(recall_v_c)
        recalls_blc_c.append(recall_blc_c)
        precisions_m_c.append(precision_m_c)
        noises.append(noise)

    compute_and_print_stats("recall_model", recalls_m_c, "%")
    compute_and_print_stats("recall_variomes", recalls_v_c, "%")
    compute_and_print_stats("recall_before_llm_calls", recalls_blc_c, "%")
    compute_and_print_stats("precision", precisions_m_c, "%")
    compute_and_print_stats("noise", noises, "%")


